css:
.crm-tix {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  box-sizing: border-box;
  container-type: inline-size;
  width: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.crm-tix .tix-head {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 14px;
  flex-wrap: wrap;
  padding: 2px 2px 0;
}
.crm-tix .tix-title { min-width: 0; }
.crm-tix .eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--muted);
}
.crm-tix .eyebrow::before {
  content: "";
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
  flex: 0 0 auto;
}
.crm-tix .tix-title h3 {
  margin: 6px 0 0;
  font: 800 clamp(18px, 3cqi, 22px)/1.15 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: -.01em;
  color: var(--ink);
}

.crm-tix .tix-tools {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
  min-width: 0;
}
.crm-tix .tix-count {
  font: 600 12px/1.2 var(--font-stack-primary, 'Inter', system-ui);
  color: var(--muted);
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}
.crm-tix .tix-search {
  box-sizing: border-box;
  font: 500 13px/1 var(--font-stack-primary, 'Inter', system-ui);
  color: var(--ink);
  background: var(--input-bg-color, var(--surface-raised));
  border: 1px solid var(--input-border-color, var(--line));
  border-radius: 10px;
  padding: 9px 12px;
  min-width: 210px;
  transition: border-color .15s ease, box-shadow .15s ease;
}
.crm-tix .tix-search::placeholder { color: var(--muted); }
.crm-tix .tix-search:hover {
  border-color: color-mix(in srgb, var(--accent) 30%, var(--line));
}
.crm-tix .tix-search:focus,
.crm-tix .tix-search:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  border-color: color-mix(in srgb, var(--accent) 45%, var(--line));
}

.crm-tix .tbl-wrap {
  box-sizing: border-box;
  overflow: auto;
  -webkit-overflow-scrolling: touch;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: var(--surface);
  max-height: 560px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  scrollbar-width: thin;
  scrollbar-color: color-mix(in srgb, var(--muted) 45%, transparent) transparent;
}
.crm-tix .tbl-wrap::-webkit-scrollbar { width: 10px; height: 10px; }
.crm-tix .tbl-wrap::-webkit-scrollbar-track { background: transparent; }
.crm-tix .tbl-wrap::-webkit-scrollbar-thumb {
  background: color-mix(in srgb, var(--muted) 42%, transparent);
  border-radius: 999px;
  border: 2px solid transparent;
  background-clip: padding-box;
}
.crm-tix .tbl-wrap::-webkit-scrollbar-thumb:hover {
  background: color-mix(in srgb, var(--muted) 62%, transparent);
  background-clip: padding-box;
}
.crm-tix .tbl-wrap:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.crm-tix table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui);
}
.crm-tix thead th {
  position: sticky;
  top: 0;
  z-index: 2;
  background: var(--surface);
  padding: 0;
  border-bottom: 1px solid var(--line);
  box-shadow: 0 1px 0 var(--line);
  white-space: nowrap;
  transition: background-color .15s ease, box-shadow .15s ease;
}
.crm-tix .th-btn {
  box-sizing: border-box;
  display: flex;
  align-items: center;
  gap: 6px;
  width: 100%;
  background: transparent;
  border: 0;
  cursor: pointer;
  padding: 11px 12px;
  text-align: left;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: .06em;
  text-transform: uppercase;
  color: var(--muted);
  transition: color .15s ease;
}
.crm-tix th.th--num .th-btn { justify-content: flex-end; text-align: right; }
.crm-tix .th-btn:hover { color: var(--ink); }
.crm-tix th.is-active {
  background: color-mix(in srgb, var(--accent) 8%, var(--surface));
  box-shadow: inset 0 -2px 0 var(--accent), 0 6px 14px -8px color-mix(in srgb, var(--accent) 45%, transparent);
}
.crm-tix th.is-active .th-btn { color: var(--accent); }
.crm-tix .th-btn:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: -2px;
  border-radius: 8px;
}
.crm-tix .th-arrow { font-size: 9px; line-height: 1; color: var(--accent); }

.crm-tix tbody td {
  padding: 10px 12px;
  border-top: 1px solid rgba(255,255,255,.06);
  color: var(--ink);
  white-space: nowrap;
  transition: background-color .12s ease, box-shadow .12s ease;
}
.crm-tix tbody tr:first-child td { border-top: 0; }
.crm-tix tbody tr:hover td { background: var(--surface-raised); }
.crm-tix tbody tr:hover td:first-child { box-shadow: inset 3px 0 0 var(--accent-2); }
.crm-tix .cell-num { text-align: right; font-variant-numeric: tabular-nums; }
.crm-tix .cell-ticket { font-weight: 700; color: var(--ink); font-variant-numeric: tabular-nums; letter-spacing: .01em; }
.crm-tix .cell-date { color: var(--muted); font-variant-numeric: tabular-nums; }

.crm-tix .cell-chip { white-space: nowrap; }
.crm-tix .chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 3px 9px;
  border-radius: 999px;
  font: 700 11px/1.3 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: .02em;
  white-space: nowrap;
  color: var(--ink);
  --chip: var(--color-gray-500, #8A8A96);
  background: color-mix(in srgb, var(--chip) 16%, var(--surface));
  border: 1px solid color-mix(in srgb, var(--chip) 38%, transparent);
}
.crm-tix .chip-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--chip);
  flex: 0 0 auto;
}
.crm-tix .chip--prio-low { --chip: var(--color-info, #34B9F3); }
.crm-tix .chip--prio-medium { --chip: #F6C453; }
.crm-tix .chip--prio-high { --chip: #FF9F45; }
.crm-tix .chip--prio-urgent { --chip: var(--color-danger, #FF5A6E); }
.crm-tix .chip--stat-open { --chip: var(--color-primary, #FFD21E); }
.crm-tix .chip--stat-in-progress { --chip: var(--color-info, #34B9F3); }
.crm-tix .chip--stat-resolved { --chip: var(--color-success, #36D399); }
.crm-tix .chip--stat-closed { --chip: var(--color-gray-500, #8A8A96); }

.crm-tix .tix-empty {
  padding: 28px 16px;
  text-align: center;
  color: var(--muted);
  font: 600 13px/1.4 var(--font-stack-primary, 'Inter', system-ui);
  border: 1px dashed var(--line);
  border-radius: 14px;
}

@container (max-width: 640px) {
  .crm-tix .tix-head { align-items: stretch; }
  .crm-tix .tix-tools { width: 100%; }
  .crm-tix .tix-count { order: 2; }
  .crm-tix .tix-search { order: 1; min-width: 0; flex: 1 1 140px; min-height: 44px; }
  .crm-tix .th-btn { min-height: 44px; }
}
@container (max-width: 480px) {
  .crm-tix .tix-search { flex: 1 1 100%; }
  .crm-tix .tix-count { width: 100%; order: 2; }
}
@media (pointer: coarse) {
  .crm-tix .tix-search { min-height: 44px; }
  .crm-tix .th-btn { min-height: 44px; }
}
@media (prefers-reduced-motion: reduce) {
  .crm-tix .th-btn,
  .crm-tix .tix-search,
  .crm-tix thead th,
  .crm-tix tbody td { transition: none; }
}
